mapper.select:
SELECT A.CONTRACT_NUM /* 계약번호 */ , A.SUB_LINK_NAME /* 고객명 */ , A.USER_SSN /* 생년월일 */ , DECODE(A.REQ_BY_TYPE, 'MM', '단말결합', 'USIM단독') AS REQ_BY_TYPE /* 구매유형 */ , A.SUBSCRIBER_NO /* 휴대폰번호 */ , A.LST_COM_ACTV_DATE /* 개통일자 */ , FN_GET_ORGNM(A.OPEN_AGNT_CD) AS OPEN_AGNT_CD /* 개통대리점 */ , A.MODEL_NAME /* 모델명 */ , A.INTM_SRL_NO /* 일련번호 */ , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS , DECODE(SUB_STATUS , 'C' , FN_GET_CODENM('MSP0004', B.SUB_STATUS_RSN_CODE) , '') AS SUB_STATUS_RSN_CODE , A.C_CONTRACT_NUM /* 계약번호 */ , A.C_SUB_LINK_NAME /* 고객명 */ , A.C_USER_SSN /* 생년월일 */ , DECODE(A.C_REQ_BY_TYPE, 'MM', '단말결합', 'USIM단독') AS C_REQ_BY_TYPE /* 구매유형 */ , A.C_SUBSCRIBER_NO /* 휴대폰번호 */ , A.C_LST_COM_ACTV_DATE /* 개통일자 */ , FN_GET_ORGNM(A.C_OPEN_AGNT_CD) AS C_OPEN_AGNT_CD /* 개통대리점 */ , A.C_MODEL_NAME /* 모델명 */ , A.C_INTM_SRL_NO /* 일련번호 */ , A.C_SUB_STATUS_DATE /* 해지일자 */ , A.C_SUB_STATUS_RSN_CODE /* 해지사유 */ , A.C_USE_DAY /* 사용기간 */ FROM MSP_REENTRANCE_MST A , MSP_JUO_SUB_INFO B WHERE 1=1 AND A.CONTRACT_NUM = B.CONTRACT_NUM
AND SUBSTR(A.LST_COM_ACTV_DATE, 1,8) BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUBSCRIBER_NO = #{searchName}
ORDER BY A.LST_COM_ACTV_DATE

SELECT A.CONTRACT_NUM /* 계약번호 */ , A.SUB_LINK_NAME /* 고객명 */ , A.USER_SSN /* 생년월일 */ , DECODE(A.REQ_BY_TYPE, 'MM', '단말결합', 'USIM단독') AS REQ_BY_TYPE /* 구매유형 */ , A.SUBSCRIBER_NO /* 휴대폰번호 */ , A.LST_COM_ACTV_DATE /* 개통일자 */ , FN_GET_ORGNM(A.OPEN_AGNT_CD) AS OPEN_AGNT_CD /* 개통대리점 */ , A.MODEL_NAME /* 모델명 */ , A.INTM_SRL_NO /* 일련번호 */ , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS , DECODE(SUB_STATUS , 'C' , FN_GET_CODENM('MSP0004', B.SUB_STATUS_RSN_CODE) , '') AS SUB_STATUS_RSN_CODE , A.C_CONTRACT_NUM /* 계약번호 */ , A.C_SUB_LINK_NAME /* 고객명 */ , A.C_USER_SSN /* 생년월일 */ , DECODE(A.C_REQ_BY_TYPE, 'MM', '단말결합', 'USIM단독') AS C_REQ_BY_TYPE /* 구매유형 */ , A.C_SUBSCRIBER_NO /* 휴대폰번호 */ , A.C_LST_COM_ACTV_DATE /* 개통일자 */ , FN_GET_ORGNM(A.C_OPEN_AGNT_CD) AS C_OPEN_AGNT_CD /* 개통대리점 */ , A.C_MODEL_NAME /* 모델명 */ , A.C_INTM_SRL_NO /* 일련번호 */ , A.C_SUB_STATUS_DATE /* 해지일자 */ , A.C_SUB_STATUS_RSN_CODE /* 해지사유 */ , A.C_USE_DAY /* 사용기간 */ FROM MSP_REENTRANCE_MST A , MSP_JUO_SUB_INFO B WHERE 1=1 AND A.CONTRACT_NUM = B.CONTRACT_NUM
AND SUBSTR(A.LST_COM_ACTV_DATE, 1,8) BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUBSCRIBER_NO = #{searchName}
ORDER BY A.LST_COM_ACTV_DATE
